async (page) => {
  // Scan for walkable path going west (lower x)
  const result = await page.evaluate(() => {
    const px = 217, py = 114;
    const walkable = [];
    // Scan west and south - trying to find path to x=166
    for (let dx = -55; dx <= 5; dx++) {
      for (let dy = -5; dy <= 20; dy++) {
        const x = px + dx, y = py + dy;
        if (!window.game.map.isColliding(x, y)) {
          walkable.push({ x, y });
        }
      }
    }
    return walkable;
  });

  // Find the most western walkable x at each y
  const byY = {};
  result.forEach(t => {
    if (!byY[t.y]) byY[t.y] = [];
    byY[t.y].push(t.x);
  });

  return Object.entries(byY)
    .sort((a, b) => Number(a[0]) - Number(b[0]))
    .map(([y, xs]) => {
      const sorted = xs.map(Number).sort((a,b)=>a-b);
      return `y=${y}: ${sorted[0]}-${sorted[sorted.length-1]} (${sorted.length} tiles)`;
    }).join('\n');
}

