async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Continue to Secret Agent (137, 171) from (154, 161)
  const steps = [
    {gridX: 147, gridY: 163},
    {gridX: 140, gridY: 165},
    {gridX: 137, gridY: 168},
    {gridX: 137, gridY: 171}
  ];

  let prevPos = {x: 154, y: 161};

  for (const step of steps) {
    await page.evaluate((pos) => window.game.input.move({ gridX: pos.gridX, gridY: pos.gridY }, false), step);
    await page.waitForTimeout(4000);

    const pos = await page.evaluate(() => window.__latestGameState.player_position);
    const moved = pos.x !== prevPos.x || pos.y !== prevPos.y;
    prevPos = pos;

    if (!moved) {
      // Try canvas click
      const dx = step.gridX - pos.x;
      const dy = step.gridY - pos.y;
      const cx = 640 + (dx / Math.max(Math.abs(dx), 1)) * 200;
      const cy = 360 + (dy / Math.max(Math.abs(dy), 1)) * 150;
      await click(cx, cy);
      await page.waitForTimeout(4000);
    }
  }

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const agent = s.nearby_entities.find(e => e.name === 'Secret Agent');
    return JSON.stringify({
      pos: s.player_position,
      hp: s.player_stats.hp,
      agent: agent ? {dist: agent.distance, cx: agent.click_x, cy: agent.click_y, on_screen: agent.on_screen, id: agent.id} : null
    });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return state;
}

