async (page) => {
  // Try DOM-based click on respawn button
  await page.evaluate(() => {
    // Try various selectors for the respawn button
    const btn = document.querySelector('#death-continue') || 
                document.querySelector('.respawn-button') ||
                document.querySelector('button[data-action="respawn"]') ||
                Array.from(document.querySelectorAll('button')).find(b => b.textContent.includes('RESPAWN'));
    if (btn) {
      btn.click();
      return 'clicked: ' + btn.id;
    }
    // Try finding by text content in all elements
    const all = Array.from(document.querySelectorAll('*'));
    const found = all.filter(el => el.textContent.trim() === 'RESPAWN' && el.children.length === 0);
    if (found.length) {
      found[0].click();
      return 'clicked text element: ' + found[0].tagName + ' ' + found[0].id;
    }
    return 'not found, document body: ' + document.body.innerHTML.substring(0, 500);
  });
  await page.waitForTimeout(3000);

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({ pos: s.player_position, hp: s.player_stats.hp, max_hp: s.player_stats.max_hp });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return state;
}

