async (page) => {
  const results = [];
  for (let i = 0; i < 5; i++) {
    const result = await page.evaluate((id) => window.__talkToNPC(id), '1-23850474');
    results.push(result);
    await page.waitForTimeout(1500);
    // Check for any dialogue bubble
    const bubble = await page.evaluate(() => {
      const bubbles = document.querySelectorAll('.bubble, .chat-bubble, [class*="bubble"]');
