async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  let kills = 0;

  // Grind rats near Blacksmith for ~15 iterations, flee if Batterfly comes close or HP drops
  for (let i = 0; i < 18; i++) {
    const state = await page.evaluate(() => {
      const s = window.__latestGameState;
      const rat = s.nearby_entities.find(e => e.type === 3 && e.name === 'Rat' && e.on_screen && e.click_x);
      const butterfly = s.nearby_entities.find(e => e.type === 3 && e.name === 'Batterfly' && e.distance < 4);
      return {
        hp: s.player_stats.hp,
        max_hp: s.player_stats.max_hp,
        level: s.player_stats.level,
        xp: s.player_stats.experience,
        rat: rat ? {cx: rat.click_x, cy: rat.click_y, dist: rat.distance, x: rat.x, y: rat.y, hp: rat.hp} : null,
        butterfly_close: butterfly ? {dist: butterfly.distance, name: butterfly.name} : null
      };
    });

    // FLEE if butterfly close or HP critical
    if (state.butterfly_close) {
      await page.evaluate(() => {
        const p = window.game.player;
        window.game.input.move({ gridX: p.gridX + 5, gridY: p.gridY + 3 }, false);
      });
      await page.waitForTimeout(3000);
      continue;
    }

    if (state.hp < state.max_hp * 0.4) {
      // Flee east to safety
      await page.evaluate(() => {
        window.game.input.move({ gridX: 215, gridY: 170 }, false);
      });
      await page.waitForTimeout(5000);
      continue;
    }

    if (!state.rat) {
      // Find next rat
      await page.evaluate(() => {
        const s = window.__latestGameState;
        const rat = s.nearby_entities.find(e => e.type === 3 && e.name === 'Rat');
        if (rat) window.game.input.move({ gridX: rat.x, gridY: rat.y }, false);
      });
      await page.waitForTimeout(3000);
      continue;
    }

    if (state.rat.dist > 2) {
      await page.evaluate((pos) => window.game.input.move({ gridX: pos.x, gridY: pos.y }, false), state.rat);
      await page.waitForTimeout(2500);
      continue;
    }

    await click(state.rat.cx, state.rat.cy);
    await page.waitForTimeout(2500);
  }

  const final = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({ hp: s.player_stats.hp, max_hp: s.player_stats.max_hp, level: s.player_stats.level, xp: s.player_stats.experience, pos: s.player_position });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return final;
}

async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Walk directly onto Rat's tile then attack
  const ratPos = await page.evaluate(() => {
    const s = window.__latestGameState;
    const rat = s.nearby_entities.find(e => e.type === 3 && e.name === 'Rat');
    return rat ? {x: rat.x, y: rat.y} : null;
  });

  if (!ratPos) return 'no rat';

  // Walk right next to rat
  await page.evaluate((pos) => window.game.input.move({ gridX: pos.x, gridY: pos.y - 1 }, false), ratPos);
  await page.waitForTimeout(3000);

  // Now attack in a tight loop
  for (let i = 0; i < 15; i++) {
    const ratState = await page.evaluate(() => {
      const s = window.__latestGameState;
      const rat = s.nearby_entities.find(e => e.type === 3 && e.name === 'Rat');
      return rat ? { hp: rat.hp, cx: rat.click_x, cy: rat.click_y, dist: rat.distance, on_screen: rat.on_screen, x: rat.x, y: rat.y } : null;
    });

    if (!ratState) break; // Rat died

    if (!ratState.on_screen || !ratState.cx) {
      // Walk to rat
      await page.evaluate((pos) => window.game.input.move({ gridX: pos.x, gridY: pos.y }, false), ratState);
      await page.waitForTimeout(2000);
      continue;
    }

    if (ratState.dist > 1) {
      await page.evaluate((pos) => window.game.input.move({ gridX: pos.x, gridY: pos.y }, false), ratState);
      await page.waitForTimeout(2000);
    }

    await click(ratState.cx, ratState.cy);
    await page.waitForTimeout(2000);
  }

  const final = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({ hp: s.player_stats.hp, level: s.player_stats.level, xp: s.player_stats.experience, pos: s.player_position, xpEvent: s.xpEvent });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return final;
}

