    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  let lastPos = {x: 232, y: 145};

  // Navigate east in multiple steps, check HP and danger each time
  for (let step = 0; step < 10; step++) {
    // Click northeast to navigate toward Dying Soldier
    await click(850, 300);
    await page.waitForTimeout(3000);

    const state = await page.evaluate(() => {
      const s = window.__latestGameState;
      const dangerous = s.nearby_entities.filter(e => e.type === 3 && e.distance < 3 && (e.hp >= 80 || e.name === ''));
      const soldier = s.nearby_entities.find(e => e.name === 'Dying Soldier');
      return {
        pos: s.player_position,
        hp: s.player_stats.hp,
        max_hp: s.player_stats.max_hp,
        dangerous: dangerous.map(m => ({name: m.name, hp: m.hp, dist: m.distance})),
        soldier: soldier ? {dist: soldier.distance, on_screen: soldier.on_screen, cx: soldier.click_x, cy: soldier.click_y, id: soldier.id} : null
      };
    });

    lastPos = state.pos;

    // Stop if near soldier
    if (state.soldier && state.soldier.dist <= 3) break;

    // Flee if HP critical
    if (state.hp < state.max_hp * 0.5) {
      await page.evaluate(() => window.game.input.move({ gridX: 231, gridY: 145 }, false));
      await page.waitForTimeout(4000);
      break;
    }

    // If we haven't moved much, try a different angle
    const moved = Math.abs(state.pos.x - lastPos.x) + Math.abs(state.pos.y - lastPos.y);
  }

  const final = await page.evaluate(() => {
    const s = window.__latestGameState;
    const soldier = s.nearby_entities.find(e => e.name === 'Dying Soldier');
    return JSON.stringify({
      pos: s.player_position,
      hp: s.player_stats.hp,
      soldier: soldier ? {dist: soldier.distance, on_screen: soldier.on_screen, cx: soldier.click_x, cy: soldier.click_y, id: soldier.id} : null
    });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return final;
}

