async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Sprint east to Dying Soldier - check position each step
  for (let i = 0; i < 20; i++) {
    const state = await page.evaluate(() => {
      const s = window.__latestGameState;
      const soldier = s.nearby_entities.find(e => e.name === 'Dying Soldier');
      return {
        pos: s.player_position,
        hp: s.player_stats.hp,
        max_hp: s.player_stats.max_hp,
        soldier: soldier ? {dist: soldier.distance, cx: soldier.click_x, cy: soldier.click_y, on_screen: soldier.on_screen, id: soldier.id} : null
      };
    });

    // If near soldier, stop and talk
    if (state.soldier && state.soldier.dist <= 2 && state.soldier.on_screen) break;

    // Flee if HP too low
    if (state.hp < 50) {
      await page.evaluate(() => window.game.input.move({ gridX: 231, gridY: 145 }, false));
      break;
    }

    if (state.soldier && state.soldier.on_screen && state.soldier.cx) {
      // Click directly on soldier
      await click(state.soldier.cx, state.soldier.cy);
    } else {
      // Keep moving east/northeast
      await click(900, 350);
    }
    await page.waitForTimeout(2500);
  }

  const final = await page.evaluate(() => {
    const s = window.__latestGameState;
    const soldier = s.nearby_entities.find(e => e.name === 'Dying Soldier');
    return JSON.stringify({
      pos: s.player_position,
      hp: s.player_stats.hp,
      soldier: soldier ? {dist: soldier.distance, cx: soldier.click_x, cy: soldier.click_y, on_screen: soldier.on_screen, id: soldier.id, quest_npc: soldier.quest_npc} : null
    });
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return final;
}

