  for (let i = 0; i < 8; i++) {
    await click(250, 600); // SW direction
    await page.waitForTimeout(2500);

    const state = await page.evaluate(() => {
      const s = window.__latestGameState;
      const vg = s.nearby_entities.find(e => e.name === 'Village Girl');
      const cat = s.nearby_entities.find(e => e.name === 'Odd-Eyed Cat');
      const butterfly = s.nearby_entities.find(e => e.name === 'Batterfly' && e.distance < 3);
      return { pos: s.player_position, hp: s.player_stats.hp, 
               vg: vg ? {dist: vg.distance, on_screen: vg.on_screen, cx: vg.click_x, cy: vg.click_y, id: vg.id} : null,
               cat: cat ? {dist: cat.distance, on_screen: cat.on_screen} : null,
               butterfly_close: !!butterfly };
    });

    if (state.butterfly_close) { await click(640, 400); await page.waitForTimeout(2000); }
    if (state.vg && state.vg.dist <= 3) break;
