        quest_npc: e.quest_npc, on_screen: e.on_screen, cx: e.click_x, cy: e.click_y, id: e.id
      }))
    };
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return JSON.stringify(state);
}

async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  // Go east to clear Guild Hall, then north, then west
  await click(1100, 300); // northeast
  await page.waitForTimeout(3000);
  await click(1100, 200); // more northeast
  await page.waitForTimeout(3000);
  await click(640, 100); // north
  await page.waitForTimeout(3000);
  await click(640, 100); // more north
  await page.waitForTimeout(3000);
  await click(200, 200); // northwest
  await page.waitForTimeout(3000);

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const sa = (gs.nearby_entities||[]).find(e=>e.name==='Secret Agent');
    return { pos: gs.player_position, hp: gs.player_stats?.hp, level: gs.player_stats?.level,
      sa: sa ? {dist:sa.distance, on_screen:sa.on_screen, cx:sa.click_x, cy:sa.click_y} : null };
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return JSON.stringify(state);
}
